// ============================================
// DYNAMIC TAILORED ANALYSIS FUNCTIONS
// ============================================

// Classify an element based on its status + peer adoption rate
function classifyElement(
  element: { isStrength: boolean; isPlanning: boolean; isAssessing: boolean; isGap: boolean },
  peerAdoptionPct: number
): string {
  if (element.isStrength && peerAdoptionPct < 35) return 'Signature Strength';
  if (element.isStrength && peerAdoptionPct >= 35) return 'Competitive Standard';
  if ((element.isGap || (!element.isStrength && !element.isPlanning && !element.isAssessing)) && peerAdoptionPct > 60) return 'Table Stakes Gap';
  if ((element.isPlanning || element.isAssessing) && peerAdoptionPct > 60) return 'Momentum Opportunity';
  if ((element.isGap || (!element.isStrength && !element.isPlanning && !element.isAssessing)) && peerAdoptionPct <= 60) return 'Aspirational Gap';
  return 'In Progress';
}

const CLASSIFICATION_STYLES: Record<string, { color: string; bg: string; border: string }> = {
  'Signature Strength': { color: '#047857', bg: '#ECFDF5', border: '#A7F3D0' },
  'Competitive Standard': { color: '#475569', bg: '#F8FAFC', border: '#CBD5E1' },
  'Table Stakes Gap': { color: '#B91C1C', bg: '#FEF2F2', border: '#FECACA' },
  'Momentum Opportunity': { color: '#1D4ED8', bg: '#EFF6FF', border: '#BFDBFE' },
  'Aspirational Gap': { color: '#B45309', bg: '#FFFBEB', border: '#FDE68A' },
  'In Progress': { color: '#3730A3', bg: '#EEF2FF', border: '#C7D2FE' },
};

// Generate tier-adaptive insights based on actual performance
// Get top evidence items for a dimension (best strength, biggest gap, in-flight item)
function getTopEvidence(
  dimNum: number,
  strengths: any[],
  gaps: any[],
  planning: any[],
  elementBenchmarks: Record<number, Record<string, { currently: number; planning: number; assessing: number; notAble: number; total: number }>>
): { 
  topStrength: { name: string; benchPct: number } | null;
  biggestGap: { name: string; benchPct: number } | null;
  inFlight: { name: string; benchPct: number } | null;
} {
  const benchmarks = elementBenchmarks[dimNum] || {};
  
  // Find top strength - prefer one where fewer peers offer it (more differentiating)
  let topStrength = null;
  if (strengths.length > 0) {
    const strengthsWithBench = strengths.map(s => {
      const bench = benchmarks[s.name] || { currently: 0, total: 1 };
      const pct = Math.round((bench.currently / (bench.total || 1)) * 100);
      return { name: s.name, benchPct: pct };
    }).sort((a, b) => a.benchPct - b.benchPct); // Sort by lowest peer % first (most differentiating)
    topStrength = strengthsWithBench[0];
  }
  
  // Find biggest gap - prefer one where most peers offer it (most impactful to address)
  let biggestGap = null;
  if (gaps.length > 0) {
    const gapsWithBench = gaps.map(g => {
      const bench = benchmarks[g.name] || { currently: 0, total: 1 };
      const pct = Math.round((bench.currently / (bench.total || 1)) * 100);
      return { name: g.name, benchPct: pct };
    }).sort((a, b) => b.benchPct - a.benchPct); // Sort by highest peer % first (biggest gap)
    biggestGap = gapsWithBench[0];
  }
  
  // Find in-flight item - prefer one where most peers already offer (fast path to catch up)
  let inFlight = null;
  if (planning.length > 0) {
    const planningWithBench = planning.map(p => {
      const bench = benchmarks[p.name] || { currently: 0, total: 1 };
      const pct = Math.round((bench.currently / (bench.total || 1)) * 100);
      return { name: p.name, benchPct: pct };
    }).sort((a, b) => b.benchPct - a.benchPct); // Sort by highest peer % (most valuable to complete)
    inFlight = planningWithBench[0];
  }
  
  return { topStrength, biggestGap, inFlight };
}

// Get 2-step roadmap for a dimension
function getTwoStepRoadmap(
  dimNum: number,
  gaps: any[],
  planning: any[],
  assessing: any[],
  elementBenchmarks: Record<number, Record<string, { currently: number; planning: number; assessing: number; notAble: number; total: number }>>
): { quickWin: { name: string; reason: string; effortTag: string; projectedLift: number } | null; strategicLift: { name: string; reason: string; effortTag: string; projectedLift: number } | null } {
  const dimBenchmarks = elementBenchmarks[dimNum] || {};

  // Build a classified + sorted pool: Table Stakes Gaps first, then Momentum Opportunities, then Aspirational Gaps
  const allItems = [
    ...gaps.map(g => ({ ...g, isGap: true, isPlanning: false, isAssessing: false, isStrength: false })),
    ...planning.map(p => ({ ...p, isGap: false, isPlanning: true, isAssessing: false, isStrength: false })),
    ...assessing.map(a => ({ ...a, isGap: false, isPlanning: false, isAssessing: true, isStrength: false })),
  ].map(item => {
    const bench = dimBenchmarks[item.name] || { currently: 0, total: 1 };
    const pct = Math.round((bench.currently / (bench.total || 1)) * 100);
    const cls = classifyElement(item, pct);
    const priority = cls === 'Table Stakes Gap' ? 0 : cls === 'Momentum Opportunity' ? 1 : cls === 'Aspirational Gap' ? 2 : 3;
    const lift = calculateElementLift(dimNum, item.name);
    return { ...item, pct, cls, priority, lift };
  }).sort((a, b) => a.priority - b.priority || b.pct - a.pct);

  // Quick win: first item in priority order (typically a table-stakes gap or momentum opportunity)
  let quickWin = null;
  if (allItems.length > 0) {
    const item = allItems[0];
    const isQuick = item.isPlanning || item.pct >= 60;
    const effortTag = isQuick ? 'Accelerate' : 'Build';
    const label = item.cls === 'Table Stakes Gap' ? 'Table-stakes gap' : item.cls === 'Momentum Opportunity' ? 'Momentum opportunity, already in development' : `${item.pct}% of participating organizations offer this`;
    quickWin = { name: item.name, reason: `${label}; ${item.pct}% of participating organizations offer this`, effortTag, projectedLift: Math.round(item.lift * 10) / 10 };
  }

  // Strategic lift: second item in priority order
  let strategicLift = null;
  if (allItems.length > 1) {
    const item = allItems[1];
    const isQuick = item.isPlanning || item.pct >= 60;
    const effortTag = isQuick ? 'Accelerate' : 'Build';
    const label = item.cls === 'Table Stakes Gap' ? 'Table-stakes gap' : item.cls === 'Momentum Opportunity' ? 'In development' : `${item.pct}% adoption among participating organizations`;
    strategicLift = { name: item.name, reason: `${label}; adding this would meaningfully expand support coverage`, effortTag, projectedLift: Math.round(item.lift * 10) / 10 };
  }

  return { quickWin, strategicLift };
}

function getActionItemsByAdoption(dimNum: number, dimensionAnalysis: any[], elementBenchmarks: Record<number, Record<string, { currently: number; total: number }>>): { accelerateItems: { name: string; pct: number; from: string; to: string }[]; buildItems: { name: string; pct: number }[] } {
  const dim = dimensionAnalysis.find(d => d.dim === dimNum);
  if (!dim) return { accelerateItems: [], buildItems: [] };
  const benchmarks = elementBenchmarks[dimNum] || {};
  const getPct = (n: string) => { const b = benchmarks[n] || { currently: 0, total: 1 }; return Math.round((b.currently / Math.max(b.total, 1)) * 100); };
  const accel: { name: string; pct: number; from: string; to: string }[] = [];
  (dim.planning || []).forEach((el: any) => accel.push({ name: el.name, pct: getPct(el.name), from: 'In Development', to: 'In Place' }));
  (dim.assessing || []).forEach((el: any) => accel.push({ name: el.name, pct: getPct(el.name), from: 'Under Review', to: 'In Development' }));
  accel.sort((a, b) => b.pct - a.pct);
  const build: { name: string; pct: number }[] = [];
  (dim.gaps || []).forEach((el: any) => build.push({ name: el.name, pct: getPct(el.name) }));
  build.sort((a, b) => b.pct - a.pct);
  return { accelerateItems: accel, buildItems: build };
}

